14	template <typename scalar_t>
15	__global__ void apply_repetition_penalties_kernel(
16	    scalar_t* __restrict__ logits,         // [num_seqs, vocab_size]
17	    const bool* __restrict__ prompt_mask,  // [num_seqs, vocab_size]
18	    const bool* __restrict__ output_mask,  // [num_seqs, vocab_size]
19	    const scalar_t* __restrict__ repetition_penalties,  // [num_seqs]
20	    const int num_seqs, const int vocab_size, const int tile_size) {
21	  // Each block handles one sequence and a tile of vocab
22	  const int seq_idx = blockIdx.x;
23	  if (seq_idx >= num_seqs) return;
24	
25	  const int tile_start = blockIdx.y * tile_size;
26	  const int tile_end = min(tile_start + tile_size, vocab_size);
27	
28	  // Load repetition penalty for this sequence
29	  const scalar_t penalty = repetition_penalties[seq_idx];
30	
31	  // Each thread processes multiple vocab items within the tile
32	  for (int vocab_idx = tile_start + threadIdx.x; vocab_idx < tile_end;
33	       vocab_idx += blockDim.x) {
34	    const int64_t idx = static_cast<int64_t>(seq_idx) * vocab_size + vocab_idx;
35	    const bool is_repeated = prompt_mask[idx] || output_mask[idx];
36	    if (is_repeated) {
37	      scalar_t logit = logits[idx];
38	      if (logit > 0) {
39	        logits[idx] = logit / penalty;
40	      } else {
41	        logits[idx] = logit * penalty;
42	      }
43	    }
44	  }
45	}
46	
47	}  // namespace vllm
